mapper.select:
SELECT p.id, p.content, p.hit_num, p.knowledge_id, p.create_time, p.update_time, COUNT(pp.id) AS paragraph_count, MAX(pp.document_id) AS document_id, MAX(pp.paragraph_id) AS paragraph_id FROM problem p LEFT JOIN problem_paragraph_mapping pp ON p.id = pp.problem_id WHERE p.knowledge_id = #{knowledgeId}
AND p.content LIKE CONCAT('%', #{content}, '%')
GROUP BY p.id, p.content, p.hit_num, p.knowledge_id, p.create_time, p.update_time ORDER BY p.create_time DESC
